// Script Continued Below
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
	//RJ -STRY0074663
	g_form.showFieldMsg("u_user_information", 
						"On save, any contact data changed for the selected contact will be updated.", 
						"info");
	g_form.setValue('u_tasker_contact.u_contact_notes', 'Loading Note...');
	var ga = new GlideAjax("ClientOrganizationalScripts");
	ga.addParam('sysparm_name', 'getContactNote');
	ga.addParam('sysparam_contactId',g_form.getValue('u_user_information'));
	ga.getXML(getContactNote, null);
	function getContactNote(response) {
		var answer = response.responseXML.documentElement.getAttribute("answer");
		g_form.setValue("u_tasker_contact.u_contact_notes",answer);
	}
}
